SELECT COUNT(DISTINCT LPP.FK_PRODBIB) AS QUANTIDADE FROM LATTES_P_PRODBIB LPP JOIN LATTES_PRODBIB LPB ON LPB.PK = LPP.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = LPP.FK_SIAPE WHERE LOWER(LPB.NATUREZA) = LOWER('resumo expandido') AND LPB.ANO = '2020' AND UPPER(S.SIGLA_CAMPUS) = 'GYN' AND LOWER(S.GENERO) = LOWER('feminino') AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%administra%' AND S.SAIU_DO_IFG = FALSE